#!/usr/bin/env node
/**
 * Retroactive repair for files generated by translate-page.mjs BEFORE
 * the apostrophe post-fix was added.
 *
 * Finds JS string literals of the form  prop: 'text with l'apostrophe'
 * that fail to parse (ASCII apostrophe inside single-quoted string), and
 * rewrites them as  prop: "text with l'apostrophe"  (double quotes).
 *
 * Usage:
 *   node scripts/fix-translated-quotes.mjs <file-or-dir> [<file-or-dir>...]
 *   node scripts/fix-translated-quotes.mjs app/fr        # whole locale
 *   node scripts/fix-translated-quotes.mjs app/fr/wav-to-text/page.js
 *   node scripts/fix-translated-quotes.mjs --all          # all 9 locales
 *
 * Output: in-place rewrite, with esbuild validation after.
 */

import fs from 'node:fs'
import path from 'node:path'
import { execFileSync } from 'node:child_process'

const LOCALES = ['fr', 'de', 'es', 'ru', 'it', 'pt', 'pl', 'ja', 'ko']

function applyFix(src) {
  // Target the contraction pattern (letter + ' + letter) only.
  // Won't false-match '/fr/slug', 'PCM 8 bits', etc.
  return src.replace(
    /([a-zA-ZÀ-ÖØ-öø-ÿĀ-ſ])'([a-zA-ZÀ-ÖØ-öø-ÿĀ-ſ])/g,
    '$1’$2'
  )
}

// Recovery: undo the over-greedy regex bug from an earlier post-fix version
// that wrapped multi-string lines like `href: '/x', label: 'Y'` as a single
// double-quoted string `href: "/x', label: 'Y"`. Detect and split.
function undoOverGreedyWrap(src) {
  // Pattern: prop: "stuff', otherProp: 'stuff"
  // Restore: prop: 'stuff', otherProp: 'stuff'
  return src.replace(
    /(\b[a-zA-Z_]\w*)\s*:\s*"([^"\n]*?)',\s*([a-zA-Z_]\w*)\s*:\s*'([^"\n]*?)"/g,
    (_, k1, v1, k2, v2) => `${k1}: '${v1}', ${k2}: '${v2}'`
  )
}

function validate(filePath) {
  try {
    execFileSync('npx', ['--yes', 'esbuild', '--loader:.js=jsx', filePath], {
      stdio: ['ignore', 'ignore', 'pipe'],
    })
    return { ok: true }
  } catch (e) {
    const stderr = e.stderr ? e.stderr.toString() : ''
    const firstLine = stderr.split('\n').find(l => l.includes('ERROR')) || stderr.slice(0, 200)
    return { ok: false, msg: firstLine.trim() }
  }
}

function fixFile(filePath) {
  const before = fs.readFileSync(filePath, 'utf8')
  // Recovery first (undo the over-greedy wrap from earlier script version),
  // then contraction fix on the recovered text.
  const recovered = undoOverGreedyWrap(before)
  const after = applyFix(recovered)
  if (before === after) {
    const v = validate(filePath)
    return { filePath, status: v.ok ? 'no-change-ok' : 'no-change-broken', detail: v.msg }
  }
  fs.writeFileSync(filePath, after)
  const v = validate(filePath)
  if (v.ok) return { filePath, status: 'fixed' }
  // Revert if our fix didn't help (shouldn't happen but defensive)
  fs.writeFileSync(filePath, before)
  return { filePath, status: 'broken-after-fix', detail: v.msg }
}

function walkPages(rootDir) {
  const out = []
  function walk(dir) {
    for (const ent of fs.readdirSync(dir, { withFileTypes: true })) {
      const p = path.join(dir, ent.name)
      if (ent.isDirectory()) walk(p)
      else if (ent.isFile() && ent.name === 'page.js') out.push(p)
    }
  }
  if (fs.existsSync(rootDir)) walk(rootDir)
  return out
}

function main() {
  const args = process.argv.slice(2)
  if (args.length === 0) {
    console.log(`Usage:
  node scripts/fix-translated-quotes.mjs <file-or-dir> [...]
  node scripts/fix-translated-quotes.mjs app/fr
  node scripts/fix-translated-quotes.mjs --all`)
    process.exit(1)
  }
  let files = []
  if (args.includes('--all')) {
    for (const loc of LOCALES) files.push(...walkPages(`app/${loc}`))
  } else {
    for (const a of args) {
      if (fs.statSync(a).isDirectory()) files.push(...walkPages(a))
      else files.push(a)
    }
  }
  let fixed = 0, ok = 0, broken = 0, badFix = 0
  for (const f of files) {
    const r = fixFile(f)
    if (r.status === 'fixed') { console.log(`✓ fixed   ${f}`); fixed++ }
    else if (r.status === 'no-change-ok') ok++
    else if (r.status === 'no-change-broken') { console.error(`✗ broken (regex didn't match) ${f}\n    ${r.detail}`); broken++ }
    else if (r.status === 'broken-after-fix') { console.error(`✗ broken after fix ${f}\n    ${r.detail}`); badFix++ }
  }
  console.log(`\nSummary: ${fixed} fixed, ${ok} already ok, ${broken} broken (regex didn't match), ${badFix} broken after fix`)
}

main()
